## Context

The project needs a new `Stepper` component added to the shadcn/ui v4 registry at
`apps/v4/registry/new-york-v4/`. Steppers are multi-step progress indicators used in
wizards, onboarding flows, and checkout processes. This follows the same compound-component
pattern as `carousel.tsx` (React context for shared state) and must conform to all
shadcn/ui v4 conventions.

No existing files are to be modified except for the two registry files where new entries
are appended in alphabetical order.

---

## Files to Create / Modify

| Action | Path |
|--------|------|
| **Create** | `apps/v4/registry/new-york-v4/ui/stepper.tsx` |
| **Create** | `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx` |
| **Edit** | `apps/v4/registry/new-york-v4/ui/_registry.ts` |
| **Edit** | `apps/v4/registry/new-york-v4/examples/_registry.ts` |

### Utilities / Patterns to Reuse
- `cn()` from `@/lib/utils` — all class merging
- `React.createContext` + custom hook pattern from `carousel.tsx` (lines 30–37)
- `data-slot` + `data-state` + `data-orientation` attribute convention (all components)
- `React.ComponentProps<"element">` for prop types (all components)
- `cva` from `class-variance-authority` — **not needed** for this component (no visual variants required)

---

## Step 1 — Create `ui/stepper.tsx`

### Architecture

Two React contexts:
1. **`StepperContext`** — shared by root, exposes `{ activeStep, orientation }`
2. **`StepperItemContext`** — shared by each item, exposes `{ step, state }`

One custom hook per context:
- `useStepper()` — throws if used outside `<Stepper />`
- `useStepperItem()` — throws if used outside `<StepperItem />`

### Exports & Implementation

```tsx
"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

// ── Context ──────────────────────────────────────────────────────────────────

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

type StepperItemContextValue = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)
const StepperItemContext = React.createContext<StepperItemContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) throw new Error("useStepper must be used within a <Stepper />")
  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) throw new Error("useStepperItem must be used within a <StepperItem />")
  return context
}

// ── Stepper (root) ────────────────────────────────────────────────────────────

function Stepper({
  orientation = "horizontal",
  activeStep,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  orientation?: "horizontal" | "vertical"
  activeStep: number
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ── StepperItem ───────────────────────────────────────────────────────────────
// state derivation: activeStep > step → "completed", === → "active", else "pending"

function StepperItem({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()
  const state: "completed" | "active" | "pending" =
    activeStep > step ? "completed" : activeStep === step ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn("flex items-center gap-2", className)}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ── StepperTrigger ────────────────────────────────────────────────────────────
// Shows step number by default; uses children if provided.
// Styled via data-state on parent StepperItem (or its own data-state attr).

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full",
        "text-sm font-medium transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        state === "completed" &&
          "bg-primary text-primary-foreground hover:bg-primary/90",
        state === "active" &&
          "border-2 border-primary bg-background text-primary",
        state === "pending" &&
          "border-2 border-muted-foreground/30 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

// ── StepperTitle ──────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

// ── StepperDescription ────────────────────────────────────────────────────────

function StepperDescription({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

// ── StepperSeparator ──────────────────────────────────────────────────────────
// Must be placed inside <StepperItem> to access StepperItemContext.
// "completed" when the parent StepperItem's state is "completed" (i.e. user
// has moved past this step, so the next step is reached).
// Orientation comes from StepperContext.

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()
  const isCompleted = state === "completed"

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "pending"}
      className={cn(
        "flex-1 shrink-0 transition-colors",
        orientation === "horizontal" ? "h-px" : "w-px self-stretch",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

// ── StepperContent ────────────────────────────────────────────────────────────
// Conditionally renders children only when step === activeStep.

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()
  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      data-step={step}
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ── Exports ───────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

---

## Step 2 — Create `examples/stepper-demo.tsx`

Key design decisions:
- `"use client"` is required because `React.useState` is used.
- Each `StepperItem` has `className="flex-1"` (except the last) so items share available width evenly.
- Inside each item, trigger + separator sit in a `flex items-center` inner div; title/description stack below.
- `StepperSeparator` lives **inside** `StepperItem` to get context — it appears visually after the trigger circle and before the next item, filling the gap between circles.
- The demo imports `Button` from `@/registry/new-york-v4/ui/button` for navigation.

