"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
    content: "Enter your email address and create a password to get started.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Complete your profile",
    content: "Add your name, photo, and other profile details.",
  },
  {
    step: 3,
    title: "Complete",
    description: "You're all set!",
    content: "Your account is ready. Welcome aboard!",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-lg flex-col gap-8">
      <Stepper activeStep={activeStep} className="w-full">
        {steps.map((s, index) => (
          <StepperItem
            key={s.step}
            step={s.step}
            className={
              index < steps.length - 1
                ? "flex-1 flex-col items-start gap-1"
                : "flex-col items-start gap-1"
            }
          >
            <div className="flex w-full items-center gap-2">
              <StepperTrigger onClick={() => setActiveStep(s.step)} />
              {index < steps.length - 1 && <StepperSeparator />}
            </div>
            <StepperTitle>{s.title}</StepperTitle>
            <StepperDescription>{s.description}</StepperDescription>
          </StepperItem>
        ))}
      </Stepper>

      {steps.map((s) => (
        <StepperContent key={s.step} step={s.step}>
          <p className="text-sm text-muted-foreground">{s.content}</p>
        </StepperContent>
      ))}

      <div className="flex justify-between">
        <Button
          variant="outline"
          onClick={() => setActiveStep((prev) => Math.max(1, prev - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          onClick={() =>
            setActiveStep((prev) => Math.min(steps.length, prev + 1))
          }
          disabled={activeStep === steps.length}
        >
          Next
        </Button>
      </div>
    </div>
  )
}

